targets.expr:
(
  sum by (action, controller, status) (
    ruby_http_requests_total{status=~"4..|5.."}
    -
    (
      ruby_http_requests_total{status=~"4..|5.."} offset 24h
      OR
      ruby_http_requests_total{status=~"4..|5.."} * 0
    )
  )
)
OR
label_replace(
  sum by (action, controller) (ruby_http_requests_total) * 0,
  "status", "none", "", ""
)

sum by (controller, action) (
  ruby_http_requests_total{controller="devise/sessions", action="new"}
  -
  (
    ruby_http_requests_total{controller="devise/sessions", action="new"} offset 24h
    OR
    ruby_http_requests_total{controller="devise/sessions", action="new"} * 0
  )
)
